func mergeCharacters(s string, k int) string {
	last := make(map[byte]int)
	var ans []byte
	for i := 0; i < len(s); i++ {
		c := s[i]
		cur := len(ans)
		if lastIdx, ok := last[c]; ok && cur-lastIdx <= k {
			continue
		}
		ans = append(ans, c)
		last[c] = cur
	}
	return string(ans)
}

